const themeInput = $('Set Theme Input').first().json;
const captionChainOutput = $('Chain 1 - Caption + Hashtags').first().json;
const imagePromptOutput = $('Chain 2 - Image Prompt Writer').first().json;
const incoming = $input.first();

const rawCaption = String(captionChainOutput.text || '').trim();

let caption = '';
let hashtags = '';

// Primary parsing
const captionMatch = rawCaption.match(/CAPTION:\s*([\s\S]*?)(?:HASHTAGS:|$)/i);
const hashtagMatch = rawCaption.match(/HASHTAGS:\s*([\s\S]*)$/i);

if (captionMatch) caption = captionMatch[1].trim();
if (hashtagMatch) hashtags = hashtagMatch[1].trim();

// Fallback 1: handle bold labels or missing exact spacing
if (!caption) {
  const altCaptionMatch = rawCaption.match(/\*{0,2}CAPTION\*{0,2}\s*:?\s*([\s\S]*?)(?:\*{0,2}HASHTAGS\*{0,2}\s*:|$)/i);
  if (altCaptionMatch) caption = altCaptionMatch[1].trim();
}

if (!hashtags) {
  const altHashtagMatch = rawCaption.match(/\*{0,2}HASHTAGS\*{0,2}\s*:?\s*([\s\S]*)$/i);
  if (altHashtagMatch) hashtags = altHashtagMatch[1].trim();
}

// Fallback 2: extract hashtags from anywhere in output
if (!hashtags) {
  const foundTags = rawCaption.match(/#[A-Za-z0-9_]+/g);
  if (foundTags && foundTags.length) {
    hashtags = foundTags.join(' ');
  }
}

// Fallback 3: if no caption label was found, use full output minus hashtags
if (!caption) {
  caption = rawCaption.replace(/#[A-Za-z0-9_]+/g, '').replace(/HASHTAGS?:?/gi, '').trim();
}

// Clean caption
caption = caption.replace(/\n{3,}/g, '\n\n').trim();
hashtags = hashtags.replace(/\n+/g, ' ').trim();

const fullText = [caption, hashtags].filter(Boolean).join('\n\n');

const binaryKey = incoming.binary ? Object.keys(incoming.binary)[0] : null;
const file = binaryKey ? incoming.binary[binaryKey] : null;
const mimeType = file?.mimeType || '';
const base64 = file?.data || null;
const isImage = mimeType.startsWith('image/');
const extension = isImage ? (mimeType.split('/')[1] || 'png') : 'bin';
const fileName = file?.fileName || `social-visual.${extension}`;
const dataUri = (base64 && isImage) ? `data:${mimeType};base64,${base64}` : null;

const captionValid = caption.length >= 180;
const hashtagsValid = hashtags.includes('#');

return [{
  json: {
    metadata: {
      generatedAt: new Date().toISOString(),
      platform: themeInput.platform,
      theme: themeInput.theme,
      tone: themeInput.tone,
      rawCaptionOutput: rawCaption
    },
    post: {
      caption,
      hashtags,
      fullText,
      characterCount: fullText.length
    },
    image: {
      prompt: imagePromptOutput.text || '',
      mimeType,
      fileName,
      dataUri,
      previewHtml: dataUri ? `<img src="${dataUri}" alt="generated image" style="max-width:100%;height:auto;border-radius:12px;" />` : null
    },
    status: {
      captionGenerated: !!caption,
      hashtagsGenerated: !!hashtags,
      captionValid,
      hashtagsValid,
      imageGenerated: !!(base64 && isImage),
      readyToPost: !!(captionValid && hashtagsValid && base64 && isImage)
    }
  },
  binary: isImage ? incoming.binary : undefined
}];
